import asyncio
from aiocoap import *
import json
import os

# Load secrets from environment variables
COAP_SECRET = os.getenv('COAP_SECRET')

# Validate input function
def validate_input(data):
    if isinstance(data, dict) and 'value' in data:
        return True
    return False

# Resource for temperature sensor
class TempSensorResource(resource.Resource):
    def __init__(self):
        super().__init__()
        self.value = 25.0  # Default temperature value

    async def render_get(self, request):
        payload = json.dumps({"temperature": self.value}).encode('utf-8')
        return aiocoap.Message(code=CONTENT, payload=payload)

    async def render_put(self, request):
        data = json.loads(request.payload.decode('utf-8'))
        if validate_input(data):
            self.value = data['value']
            return aiocoap.Message(code=CHANGED)
        else:
            return aiocoap.Message(code=BAD_REQUEST)

# Resource for light actuator
class LightActuatorResource(resource.Resource):
    def __init__(self):
        super().__init__()
        self.state = False  # Default light state

    async def render_get(self, request):
        payload = json.dumps({"light": self.state}).encode('utf-8')
        return aiocoap.Message(code=CONTENT, payload=payload)

    async def render_put(self, request):
        data = json.loads(request.payload.decode('utf-8'))
        if validate_input(data):
            self.state = data['value']
            return aiocoap.Message(code=CHANGED)
        else:
            return aiocoap.Message(code=BAD_REQUEST)

# Main function to start the CoAP server
async def main():
    root = resource.Resource()
    root.add_resource(['sensors', 'temp'], TempSensorResource())
    root.add_resource(['actuators', 'light'], LightActuatorResource())

    # Create CoAP server
    await Context.create_server_context(root)

    print("CoAP server running...")
    await asyncio.get_event_loop().create_future()  # Run forever

if __name__ == "__main__":
    asyncio.run(main())